const fs = require("fs"), path = require("path"), crypto = require("crypto")
const CD = path.resolve(process.cwd(), "content")
const DIRS = { R: path.join(CD,"reviews"), B: path.join(CD,"best"), I: path.join(CD,"industries"), U: path.join(CD,"use-cases") }

// Content catalog
const CAT = { R:[], C:[], B:[], I:[], U:[], G:[], BL:[], S:[], GL:[] }
function bc() {
  for (const d of ["reviews","comparisons","best","industries","use-cases","guides","blog","statistics","glossary"]) {
    try { for (const f of fs.readdirSync(path.join(CD,d)).filter(f=>f.endsWith(".json"))) {
      const j = JSON.parse(fs.readFileSync(path.join(CD,d,f),"utf-8"))
      if (d==="reviews") CAT.R.push({slug:j.slug,name:j.name,cat:j.category,rating:j.rating,pr:j.priceRange})
      else if (d==="comparisons") CAT.C.push({slug:j.slug,cat:j.category})
      else if (d==="best") CAT.B.push({slug:j.slug,cat:j.category})
      else if (d==="industries") CAT.I.push({slug:j.slug,name:j.industry||j.slug,cat:j.industry||j.slug,compliance:j.compliance||[]})
      else if (d==="use-cases") CAT.U.push({slug:j.slug,cat:j.category,name:j.slug})
      else if (d==="guides") CAT.G.push({slug:j.slug,cat:j.category})
      else if (d==="blog") CAT.BL.push({slug:j.slug})
      else if (d==="statistics") CAT.S.push({slug:j.slug,cat:j.category})
      else if (d==="glossary") CAT.GL.push({slug:j.slug})
    }} catch(e) {}
  }
}

function link(t,h) { return '<a href="'+h+'">'+t+'</a>' }
function pickN(a,n,s) {
  const r = [...a]
  for (let i=r.length-1;i>0;i--) { const h = crypto.createHash("md5").update(s+"-"+i).digest().readUInt32BE(0); const j=Math.abs(h)%(i+1); [r[i],r[j]]=[r[j],r[i]] }
  return r.slice(0,Math.min(n,r.length))
}

