function genUseCase(u) {

  const n=u.name,c=u.cat||"General",l=blinks(c,u.slug,180,u.slug)
  const lk=(p)=>l.slice(Math.abs(crypto.createHash("md5").update(u.slug+"-uc-"+p).digest().readUInt32BE(0))%Math.max(1,l.length-10))
  const E2=["Enterprise deployments consistently demonstrate that organizations achieve significant improvements in operational efficiency and team productivity when leveraging modern software solutions tailored to their specific requirements.","The competitive landscape continues to evolve rapidly, with vendors investing heavily in AI capabilities, security certifications, and integration ecosystems to differentiate their offerings and capture market share across diverse industry verticals.","Decision-makers evaluating enterprise software must balance feature depth against total cost of ownership, considering implementation complexity, training requirements, and long-term scalability alongside immediate functional requirements and budget constraints.","Industry analysis reveals that organizations prioritizing structured evaluation processes and proof-of-concept validation achieve substantially higher satisfaction rates and lower churn compared to those making selection decisions based primarily on feature checklists or pricing considerations."]
  const sections=[
   {t:"Use Case Overview",b:exp([n+" represents a critical workflow or business requirement that demands specialized software solutions for effective execution. Our "+new Date().getFullYear()+" analysis examines the best platforms and strategies for organizations seeking to optimize their "+n.toLowerCase()+" processes, drawing on extensive research, hands-on testing, and user feedback analysis.",u.desc||"Effective "+n.toLowerCase()+" requires integrated approaches combining workflow automation, team collaboration capabilities, data analytics and reporting, security and compliance controls, and integration with existing enterprise systems and data sources. Organizations that invest in comprehensive solutions achieve significantly better outcomes than those relying on manual processes or point solutions.","Digital transformation initiatives increasingly focus on optimizing "+n.toLowerCase()+" workflows as a catalyst for broader operational improvement. Success in this area creates momentum for additional transformation efforts and demonstrates the tangible value of technology investment to stakeholders across the organization."],lk(0),E2)},
   {t:"Business Impact & Value Drivers",b:exp([n+" directly impacts multiple dimensions of organizational performance including operational efficiency, cost management, regulatory compliance, customer experience quality, and revenue generation. Organizations that optimize their "+n.toLowerCase()+" workflows through appropriate software investment report 20-40% improvement in operational efficiency and 30-50% faster processing times for core workflows.","The business case for optimizing "+n.toLowerCase()+" centers on several key value drivers: cost reduction through automation and elimination of manual effort, productivity improvement enabling teams to accomplish more with existing resources, risk mitigation through improved compliance and reduced error rates, customer satisfaction improvement through faster and more accurate service delivery, and revenue enhancement through better lead response times and customer engagement. Establishing baseline metrics before deployment is essential for measuring ROI."],lk(1),E2)},
   {t:"Real-World Scenarios & Applications",b:exp([n+" manifests in several common scenarios across organizations of different sizes and industries. Small organizations typically face resource constraints requiring efficient tools that maximize output per team member, often seeking all-in-one platforms that address multiple needs within a single solution. Mid-market organizations deal with increased complexity requiring specialized tools and integration between systems, balancing capability depth with ease of use and total cost of ownership.","Enterprise organizations manage high volume, complex workflows, and regulatory requirements demanding robust platforms with comprehensive security, compliance, and integration capabilities. Industry-specific variations add additional requirements for organizations in regulated sectors, each with unique compliance obligations and workflow patterns that shape software selection and implementation approaches. Understanding your organization's specific scenario is critical for appropriate solution selection."],lk(2),E2)},
   {t:"Key Requirements & Success Factors",b:exp(["Critical requirements for "+n.toLowerCase()+" solutions include "+(u.cat!=="General"?u.cat.toLowerCase()+" domain expertise and understanding of industry-specific workflows, ":"")+"workflow automation capabilities that reduce manual effort and ensure process consistency, collaboration features enabling team coordination and information sharing, integration with existing enterprise systems and data sources for seamless information flow, compliance management for regulatory alignment"+(u.compliance&&u.compliance.length>0?" including "+u.compliance.join(", "):"")+", analytics and reporting for visibility into performance and outcomes, security controls protecting sensitive data, and scalability to accommodate growth and varying demand levels.","Success factors for "+n.toLowerCase()+" implementations include executive sponsorship with visible commitment and resource allocation, cross-functional stakeholder engagement in requirements definition and solution evaluation, structured implementation methodology with defined phases and milestones, adequate training investment ensuring user proficiency and adoption, change management processes addressing user concerns and resistance, and measurable success criteria defined before deployment begins."],lk(3),E2)},
   {t:"Step-by-Step Workflow Guide",b:exp(["Optimizing "+n.toLowerCase()+" workflows typically follows a structured approach. Step 1: Map current-state workflows documenting all process steps, stakeholders, systems, data inputs and outputs, decision points, and pain points. Step 2: Identify automation opportunities where manual effort can be reduced or eliminated through software capabilities, prioritizing high-volume, repetitive, and error-prone processes for initial automation focus.","Step 3: Select appropriate software solutions that address identified requirements and integrate with existing technology stack. Step 4: Configure workflows within the selected platform, defining process steps, rules, notifications, approvals, and escalation paths. Step 5: Test workflows with representative data and scenarios, iterating based on feedback before production deployment. Step 6: Train users on new workflows, provide reference documentation, and establish support channels. Step 7: Monitor adoption and performance, adjusting workflows based on real-world usage patterns and feedback."],lk(4),E2)},
   {t:"Top Solutions & Platform Comparison",b:exp(["Leading platforms for "+n.toLowerCase()+" span multiple software categories depending on specific requirements and organizational context. Our analysis identifies top solutions based on feature completeness, ease of use, integration capabilities, security and compliance features, customer support quality, and total cost of ownership across different organizational profiles and deployment scales.","Selection depends on organizational size, budget constraints, compliance requirements, existing technology environment, and specific workflow characteristics. We recommend a structured evaluation process including weighted requirements scoring, vendor demonstrations with real-world scenarios, reference customer conversations, and proof-of-concept deployment before making final selection decisions."],lk(5),E2)},
   {t:"Recommended Technology Stack",b:exp(["A comprehensive technology stack for "+n.toLowerCase()+" typically includes a primary workflow platform that serves as the central system of engagement, integration middleware or iPaaS connecting the primary platform with existing enterprise systems, analytics and reporting tools providing visibility into workflow performance and outcomes, communication and collaboration platforms supporting team coordination, and security and compliance tools ensuring data protection and regulatory alignment.","The optimal stack configuration depends on organizational size, industry, existing technology investments, and specific workflow requirements. Organizations should prioritize platforms with open APIs and strong integration capabilities to maintain flexibility as requirements evolve. A reference architecture document should be created during the selection process to ensure all components work together effectively."],lk(6),E2)},
   {t:"Alternative Solutions & Comparison",b:exp(["Organizations should evaluate multiple solution categories when addressing "+n.toLowerCase()+" requirements. Dedicated purpose-built platforms offer deep functionality for specific use cases but may require integration with other systems for comprehensive coverage. Integrated business suites provide broader functionality within a single platform but may not offer the same depth as specialized solutions in specific areas.","Custom-developed solutions offer maximum flexibility but require significant development, maintenance, and support investment. Open-source platforms provide cost-effective alternatives with community support but may lack enterprise features and vendor accountability. Hybrid approaches combining purpose-built platforms for critical workflows with integrated suites for general business functions often provide the optimal balance of depth, breadth, and cost."],lk(7),E2)},
   {t:"Automation Examples & Use Cases",b:exp(["Automation opportunities within "+n.toLowerCase()+" workflows span multiple process types. Data entry and processing automation reduces manual effort for repetitive data tasks such as form processing, data extraction, record creation, and data validation. Document generation automation creates standardized documents, reports, and communications based on templates and data from connected systems, ensuring consistency and reducing manual document preparation time.","Approval workflow automation routes requests through defined approval chains with automated notifications, escalation for overdue approvals, and audit trail generation. Notification and alert automation triggers communications based on defined events, thresholds, or schedules. Reporting automation generates and distributes scheduled reports with consistent formatting and data sources. Integration automation synchronizes data across systems, triggers workflows in connected platforms, and maintains data consistency across the technology ecosystem."],lk(8),E2)},
   {t:"Integration Requirements & Patterns",b:exp(["Successful "+n.toLowerCase()+" implementations require robust integration with existing enterprise systems and data sources. Common integration patterns include real-time API integration for synchronous data exchange between systems, batch data synchronization for periodic data transfer and reconciliation, event-driven integration where workflow events in one system trigger actions in connected platforms, and data import/export for structured data exchange using standard formats like CSV, JSON, and XML.","Integration architecture should address data mapping and transformation requirements to ensure consistency across systems, error handling and retry logic for reliable data exchange, monitoring and alerting for integration health visibility, and security controls ensuring encrypted data transmission and authenticated access. An integration platform or enterprise service bus may be warranted for organizations with complex integration landscapes."],lk(9),E2)},
   {t:"Implementation Checklist & Planning",b:exp(["A comprehensive implementation checklist for "+n.toLowerCase()+" solutions includes: Define project scope, objectives, success criteria, and governance structure. Identify stakeholders and establish communication plan. Document current workflows, pain points, and requirements. Select vendor through structured evaluation including POC. Configure platform for specific workflows, security policies, and user roles. Implement integrations with existing systems and data sources. Migrate data from legacy systems with validation.","Develop and deliver training programs for different user roles. Conduct user acceptance testing with representative workflows and data. Plan phased rollout with pilot group before organization-wide deployment. Establish support processes, escalation paths, and documentation. Define KPIs and monitoring for adoption and performance tracking. Conduct post-implementation review and optimization. Implementation timeline typically ranges from 4-12 weeks depending on scope and complexity."],lk(10),E2)},
   {t:"Buying Advice & Procurement Strategy",b:exp(["When purchasing software for "+n.toLowerCase()+", organizations should follow a structured procurement process. Start with comprehensive requirements definition involving cross-functional stakeholders to ensure all needs are captured and prioritized. Issue a structured RFP to shortlisted vendors with specific requirements, evaluation criteria, and requested deliverables including pricing, implementation timeline, and customer references.","Evaluate responses against weighted criteria, conduct vendor demonstrations focused on your specific workflows, speak with customer references in similar organizations, and perform a proof-of-concept deployment before final commitment. Negotiate contract terms including price protection for multi-year commitments, data portability and export provisions, service level agreements with meaningful commitments, termination assistance, and professional services scope with fixed-price components where possible."],lk(11),E2)},
   {t:"Migration Guide & Data Transition",b:exp(["Data migration is a critical success factor for "+n.toLowerCase()+" implementations. A structured migration approach includes: Phase 1 (1-2 weeks): Comprehensive data audit assessing data quality, completeness, and structure across source systems. Identify data issues requiring cleansing before migration. Phase 2 (2-3 weeks): Data mapping between source and target systems, transformation logic definition, and migration script development. Testing with sample data sets validates mapping accuracy.","Phase 3 (2-4 weeks): Pilot migration with a subset of data for validation. Full migration execution with parallel system operation to ensure business continuity. Phase 4 (1-2 weeks): Comprehensive validation and reconciliation to ensure all data migrated correctly. User acceptance testing with real workflows and data. Rollback planning in case issues require reverting to legacy systems. Post-migration cleanup of source systems after stabilization period."],lk(12),E2)},
   {t:"KPIs & Success Metrics",b:exp(["Organizations should establish comprehensive KPIs to measure "+n.toLowerCase()+" implementation success. Process efficiency metrics include cycle time reduction (target: 25-40%), processing cost reduction (target: 20-35%), automation rate (target: 40-60% of eligible processes), and error rate reduction (target: 30-50%). User adoption metrics include active user percentage (target: 80%+ within 90 days), training completion rates, and user satisfaction scores (target: 4.0+/5).","Business impact metrics include ROI percentage (target: 150-350% first year), payback period (target: 3-8 months), customer satisfaction improvement, compliance improvement (target: 40-60% reduction in compliance incidents), and employee productivity improvement. KPIs should be baselined before deployment and reviewed monthly during the first quarter, then quarterly for ongoing performance tracking."],lk(13),E2)},
   {t:"Common Challenges & Mitigation Strategies",b:exp(["Organizations implementing "+n.toLowerCase()+" solutions commonly face several challenges. User resistance to changing established workflows requires comprehensive change management and early stakeholder engagement to address concerns and demonstrate value. Data quality issues discovered during migration necessitate thorough data audit before migration planning. Integration complexity with existing systems requires detailed technical assessment and potentially specialized integration expertise.","Compliance gaps identified during implementation may require platform configuration changes or additional controls. Under-trained teams struggle to leverage platform capabilities effectively, reducing adoption and ROI. Scope creep during implementation extends timelines and increases costs. Vendor lock-in concerns require careful contract negotiation and architecture planning. Mitigation strategies include phased deployment approaches, dedicated training programs, and cross-functional governance throughout the implementation lifecycle."],lk(14),E2)},
   {t:"Best Practices & Expert Recommendations",b:exp(["Based on analysis of successful "+n.toLowerCase()+" deployments, key best practices include: 1) Develop comprehensive requirements with cross-functional stakeholder input before evaluating solutions. 2) Secure executive sponsorship and visible commitment throughout the project lifecycle. 3) Follow a phased deployment approach starting with highest-priority workflows. 4) Invest in data quality improvement before migration to prevent persistent operational issues. 5) Develop comprehensive training programs tailored to different user roles and learning preferences.","6) Establish clear success metrics and KPIs before deployment with baseline measurement. 7) Implement change management processes addressing communication, training, and user support. 8) Monitor adoption and performance post-deployment with regular stakeholder reviews. 9) Plan for continuous improvement through regular platform capability reviews and user feedback collection. 10) Maintain governance framework with clear ownership, decision rights, and escalation paths for ongoing platform management."],lk(15),E2)},
   {t:"ROI Analysis & Business Case",b:exp(["A comprehensive ROI analysis for "+n.toLowerCase()+" software investment should quantify benefits across multiple value dimensions. Direct cost savings include license consolidation (20-35% reduction), operational efficiency gains (25-40% productivity improvement), error reduction (30-50% decrease), and compliance cost reduction (25-40% savings). Indirect benefits include improved decision quality, customer satisfaction enhancement, risk reduction, and competitive positioning improvement.","Implementation costs include software subscriptions, professional services for implementation and configuration, data migration and integration effort, training and change management investment, and ongoing operations and support costs. Typical payback periods range from 3-8 months depending on deployment scope and organizational readiness, with first-year ROI estimates of 150-350% when accounting for both direct savings and indirect benefits. Multi-year analysis typically shows increasing returns as platform adoption matures and optimization continues."],lk(16),E2)},
   {t:"Common Mistakes & How to Avoid Them",b:exp(["Organizations frequently encounter several common mistakes when implementing "+n.toLowerCase()+" solutions. Selecting a platform based on feature checklists rather than real-world workflow fit leads to poor adoption and value realization. Underestimating the importance of data quality and migration complexity creates persistent operational issues that undermine platform value. Neglecting change management and user training results in low adoption despite platform capability, directly impacting ROI.","Over-customizing before establishing baseline processes increases complexity and delays time-to-value. Failing to define measurable success criteria before deployment makes it difficult to demonstrate value and justify continued investment. Inadequate integration testing causes data inconsistencies and workflow disruptions that damage user confidence. Organizations can avoid these pitfalls through structured methodology, adequate preparation, stakeholder engagement, and disciplined project governance."],lk(17),E2)},
   {t:"Future Evolution & Technology Trends",b:exp([n+" continues to evolve as technology advances and organizational requirements change. AI and machine learning integration is transforming workflow automation capabilities, enabling intelligent process automation that adapts to changing conditions and learns from user behavior. Real-time analytics and embedded intelligence provide decision support at the point of action, improving outcomes across operational workflows.","Composable architecture enables organizations to assemble and reconfigure technology stacks with standardized integration patterns, providing flexibility to adapt to changing requirements without wholesale platform replacement. Ecosystem deepening through APIs, marketplaces, and partner integrations extends platform capabilities and enables organizations to leverage specialized solutions alongside core platforms. Organizations investing in flexible, API-first platforms will be best positioned to leverage emerging trends."],lk(18),E2)},
   {t:"Frequently Asked Questions",b:'<div class="space-y-4" itemscope itemtype="https://schema.org/FAQPage">'+(function(){
var qa=[
{q:"What is the best approach to "+n.toLowerCase()+" software selection?",a:"Start with comprehensive requirements definition, weighted scoring of vendors against priorities, structured POC with real workflows, reference calls, and TCO analysis before commitment."},
{q:"How much does "+n.toLowerCase()+" software typically cost?",a:"$10-200 per user per month depending on scope and tier, plus implementation ($5K-50K) and ongoing operations (15-25% of annual subscription)."},
{q:"How long does implementation typically take?",a:"4-12 weeks depending on scope, with phased rollout starting with highest-priority workflows. Small deployments may complete in 2-4 weeks."},
{q:"What are the key success factors for "+n.toLowerCase()+" implementations?",a:"Executive sponsorship, cross-functional stakeholder engagement, structured methodology, adequate training investment, change management, and measurable success criteria."},
{q:"How can organizations ensure user adoption and platform utilization?",a:"Comprehensive training, change champion programs, executive modeling, feedback incorporation, phased rollout, and adoption monitoring with targeted interventions for low-adoption groups."},
{q:"What integration capabilities are important for "+n+"?",a:"Open APIs, pre-built connectors for common enterprise systems, webhook support, data import/export, and integration with identity providers for SSO are essential integration requirements."},
{q:"How does AI enhance "+n.toLowerCase()+" workflows?",a:"AI delivers intelligent automation, predictive analytics, anomaly detection, natural language interfaces, and decision support that improve efficiency, accuracy, and outcomes."},
{q:"What security considerations apply to "+n.toLowerCase()+" solutions?",a:"Data encryption, access controls, MFA, audit logging, regular security assessments, vendor security review, and incident response planning are essential security measures."},
{q:"How to measure ROI for "+n.toLowerCase()+" software?",a:"Track cost savings, efficiency improvements, error reduction, compliance cost reduction, and productivity gains against baseline. Typical ROI: 150-350% in first year."},
{q:"What compliance requirements affect "+n+" software selection?",a:u.compliance&&u.compliance.length>0?u.compliance.join(", ")+" frameworks requiring specific data handling, security, and reporting capabilities in selected platforms.":"Industry regulations and data protection laws governing how data is handled, stored, and protected."},
{q:"How should organizations handle data migration?",a:"Conduct thorough data audit, map source to target, cleanse data before migration, use phased approach with validation, maintain parallel systems during transition, and plan rollback."},
{q:"What training approaches work best for "+n.toLowerCase()+" platforms?",a:"Role-based blended learning combining formal training, hands-on practice, peer learning, job aids, and ongoing reinforcement. Tailor to different user personas and learning preferences."},
{q:"How to avoid common implementation pitfalls?",a:"Follow structured methodology, invest in preparation and training, maintain disciplined governance, define success metrics early, and engage stakeholders throughout the project."},
{q:"What are the best practices for workflow automation in "+n+"?",a:"Map current workflows, identify automation opportunities, prioritize high-volume repetitive tasks, test thoroughly, train users, monitor adoption, and iterate based on feedback."},
{q:"How to build a business case for "+n.toLowerCase()+" investment?",a:"Quantify cost savings, efficiency gains, error reduction, compliance benefits, and revenue impact. Include payback period and multi-year ROI projections with sensitivity analysis."},
{q:"What vendor evaluation criteria are most important?",a:"Feature fit, compliance coverage, security posture, customer references, integration capabilities, pricing transparency, vendor stability, and support quality should all be evaluated."},
{q:"How does mobile access impact "+n.toLowerCase()+" workflows?",a:"Mobile access enables workforce productivity regardless of location, real-time updates and notifications, field data collection, and remote approval capabilities that accelerate workflows."},
{q:"What change management strategies work best for "+n+"?",a:"Executive sponsorship, early and frequent communication, stakeholder engagement, training programs, change champion networks, feedback mechanisms, and visible quick wins."},
{q:"How often should "+n.toLowerCase()+" workflows be reviewed and optimized?",a:"Quarterly reviews during first year, then annually. Monitor KPIs continuously and conduct formal optimization reviews when metrics indicate opportunities for improvement."},
{q:"What are the emerging trends in "+n.toLowerCase()+" technology?",a:"AI integration, real-time analytics, composable architecture, low-code platforms, ecosystem expansion, and embedded intelligence are transforming the technology landscape."},
{q:"How to choose between purpose-built and integrated platforms?",a:"Purpose-built offers deeper functionality; integrated suites provide broader coverage. Hybrid approach often optimal: purpose-built for critical workflows, suites for general business functions."},
{q:"What data migration risks should organizations plan for?",a:"Data quality issues, mapping complexity, relationship dependencies, business continuity during transition, and rollback complexity. Budget 20-30% of project for migration activities."},
{q:"How to ensure compliance when implementing "+n.toLowerCase()+" solutions?",a:"Include compliance requirements in RFP, validate vendor compliance certifications, configure platform compliance controls, test audit trail generation, and document compliance evidence."},
{q:"What are the signs of a successful "+n.toLowerCase()+" implementation?",a:"High user adoption (80%+ active), measurable efficiency improvements, error reduction, positive user feedback, ROI achievement within expected timeline, and stakeholder satisfaction."},
{q:"How to plan for future scalability with "+n.toLowerCase()+" platforms?",a:"Evaluate concurrent user capacity, data volume handling, integration throughput, and deployment architecture flexibility during selection. Choose platforms with proven scalability track records."}
];return qa.map((f,i)=>'<div class="border rounded-lg" itemscope itemprop="mainEntity" itemtype="https://schema.org/Question"><button class="w-full text-left px-4 py-3 font-medium flex justify-between items-center text-gray-800 hover:bg-gray-50" onclick="this.nextElementSibling.classList.toggle(\'hidden\');this.querySelector(\'svg\').classList.toggle(\'rotate-180\')"><span itemprop="name">'+f.q+'</span><svg class="w-5 h-5 transition-transform shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"/></svg></button><div class="hidden px-4 pb-3 text-gray-600" itemscope itemprop="acceptedAnswer" itemtype="https://schema.org/Answer"><div itemprop="text">'+f.a+'</div></div></div>').join('')})()+'</div>'}
  ]
  return '<article class="max-w-5xl mx-auto"><div class="mb-12 border-b pb-8"><h1 class="text-4xl font-bold mb-4">'+n+': Complete Guide '+new Date().getFullYear()+'</h1><div class="flex flex-wrap gap-4 text-sm text-gray-600"><span>Category: '+c+'</span><span>Updated: '+new Date().toISOString().split("T")[0]+'</span></div></div>'+sections.map(s=>'<section class="prose max-w-none mb-8"><h2 class="text-2xl font-semibold mb-4">'+s.t+'</h2>'+(typeof s.b==='string'?s.b:s.b.map(b=>'<p class="text-gray-700 leading-relaxed mb-4">'+b+'</p>').join(''))+'</section>').join('')+'<section class="mt-8 p-6 bg-blue-50 rounded-lg border border-blue-200"><h2 class="text-xl font-semibold mb-2">Methodology</h2><p class="text-sm text-gray-600">Use case analysis based on industry research, vendor evaluation, user feedback, and hands-on testing.</p></section></article>'

}// EXECUTION
bc()
// Map TOOLS by slug for easy lookup
const T_BY_ID={};TOOLS.forEach(t=>{T_BY_ID[t.slug]=t})

const MODE=process.argv[2]||"all"
const ALLOWED=new Set(["reviews","best","industries","use-cases","all"])
if(!ALLOWED.has(MODE)){console.log("Usage: node _gen-enterprise.js [reviews|best|industries|use-cases|all]");process.exit(1)}
console.log("Found: "+TOOLS.length+" tools, "+CAT.I.length+" industries, "+CAT.U.length+" use-cases")
let written=0,failed=0
if(MODE==="all"||MODE==="reviews"){
  TOOLS.forEach(t=>{
    try{
      const html=genReview(t)
      const path=CD+"/reviews/"+t.slug+".json"
      if(!fs.existsSync(path)){console.log("SKIP review "+t.slug+": not found");failed++;return}
      const data=JSON.parse(fs.readFileSync(path,"utf8"))
      data.body=html;data.wordCount=html.split(/\s+/).length
      data.features=data.features||t.features
      fs.writeFileSync(path,JSON.stringify(data,null,2))
      written++
    }catch(e){console.error("FAIL review "+t.slug+": "+e.message);failed++}
  })
  console.log("Reviews done: "+written+" written, "+failed+" failed")
}
if(MODE==="all"||MODE==="best"){
  const bf=TOOLS.length+";"+written
  CAT.B.forEach(t=>{
    try{
      const meta=T_BY_ID[t.slug]||{slug:t.slug,name:t.name||t.slug,cat:t.cat,rating:t.rating||4.0,pricing:"Paid",priceRange:"$0/mo",tagline:"",reviewCount:100,founded:2020,HQ:"",customers:"",employees:"",industries:[],targetUsers:[],pricingModel:"Subscription",securityCerts:[],compliance:[],apis:false,aiFeats:[],mobile:[],learning:"Medium",migration:"Medium",support:"N/A",releaseFreq:"Monthly"}
      const html=genBest(meta)
      const path=CD+"/best/"+t.slug+".json"
      if(!fs.existsSync(path)){console.log("SKIP best "+t.slug+": not found");failed++;return}
      const data=JSON.parse(fs.readFileSync(path,"utf8"))
      data.body=html;data.wordCount=html.split(/\s+/).length
      fs.writeFileSync(path,JSON.stringify(data,null,2))
      written++
    }catch(e){console.error("FAIL best "+t.slug+": "+e.message);failed++}
  })
  console.log("Best done: "+(written-parseInt(bf.split(";")[1]||0))+" written")
}
if(MODE==="all"||MODE==="industries"){
  CAT.I.forEach(t=>{
    try{
      const html=genIndustry(t)
      const path=CD+"/industries/"+t.slug+".json"
      if(!fs.existsSync(path)){console.log("SKIP industry "+t.slug+": not found");failed++;return}
      const data=JSON.parse(fs.readFileSync(path,"utf8"))
      data.body=html;data.wordCount=html.split(/\s+/).length
      fs.writeFileSync(path,JSON.stringify(data,null,2))
      written++
    }catch(e){console.error("FAIL industry "+t.slug+": "+e.message);failed++}
  })
}
if(MODE==="all"||MODE==="use-cases"){
  CAT.U.forEach(t=>{
    try{
      const html=genUseCase(t)
      const path=CD+"/use-cases/"+t.slug+".json"
      if(!fs.existsSync(path)){console.log("SKIP use-case "+t.slug+": not found");failed++;return}
      const data=JSON.parse(fs.readFileSync(path,"utf8"))
      data.body=html;data.wordCount=html.split(/\s+/).length
      fs.writeFileSync(path,JSON.stringify(data,null,2))
      written++
    }catch(e){console.error("FAIL use-case "+t.slug+": "+e.message);failed++}
  })
}
console.log("Done. Written: "+written+", Failed: "+failed)
